27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	};
38	
39	const blockOfThreeDiscount = (count: number): number =>
40	  count === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
41	
42	const sumBasePremiums = (items: Item[]): number => {
43	  const ungroupedTotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
44	  const runeCount = items.filter((i) => i.type === "rune").length;
45	  return ungroupedTotal - blockOfThreeDiscount(runeCount);
46	};
47	
48	const quote = (step: QuoteStep): QuoteResult => {
49	  const itemsBase = sumBasePremiums(step.items);
50	  const firstContractSurcharge = itemsBase * FIRST_CONTRACT_SURCHARGE_RATE;
51	  const premium = Math.ceil(itemsBase + firstContractSurcharge + PROCESSING_FEE);
52	  return { premium };
53	};
54	
55	export const runScenario = (scenario: Scenario): ScenarioResult => {
56	  const results = scenario.steps.map(quote);
57	  return { results };
58	};
